const skillCounts = {};
const categoryCounts = {};

for (const item of items) {

  const skills = [

    ...(item.json["Important Skills"]
      ? item.json["Important Skills"]
          .split(",")
          .map(s => s.trim())
      : []),

    ...(item.json.tags || [])
  ];

  // Prevent duplicate counting
  const uniqueSkills =
    [...new Set(skills)];

  for (let skill of uniqueSkills) {

    skill =
      skill.toLowerCase().trim();

    if (!skill) continue;

    // ----------------------------
    // SKILL FREQUENCY
    // ----------------------------

    skillCounts[skill] =
      (skillCounts[skill] || 0) + 1;

    // ----------------------------
    // CATEGORY GROUPING
    // ----------------------------

    // CLOUD

    if (
      [
        "aws",
        "azure",
        "gcp",
        "cloud",
        "cloud security",
        "cloud computing"
      ].includes(skill)
    ) {

      categoryCounts["Cloud"] =
        (categoryCounts["Cloud"] || 0) + 1;
    }

    // DEVOPS

    if (
      [
        "docker",
        "kubernetes",
        "devops",
        "jenkins",
        "ansible",
        "ci/cd"
      ].includes(skill)
    ) {

      categoryCounts["DevOps"] =
        (categoryCounts["DevOps"] || 0) + 1;
    }

    // CYBERSECURITY

    if (
      [
        "security",
        "cybersecurity",
        "siem",
        "pentesting",
        "vulnerability management",
        "threat intelligence"
      ].includes(skill)
    ) {

      categoryCounts["Cybersecurity"] =
        (categoryCounts["Cybersecurity"] || 0) + 1;
    }

    // BACKEND

    if (
      [
        "python",
        "flask",
        "backend",
        "backend engineering",
        "api",
        "apis",
        "node.js",
        "java",
        "sql"
      ].includes(skill)
    ) {

      categoryCounts["Backend Engineering"] =
        (categoryCounts["Backend Engineering"] || 0) + 1;
    }

    // AI / ML

    if (
      [
        "tensorflow",
        "ai",
        "ml",
        "machine learning",
        "deep learning",
        "pytorch"
      ].includes(skill)
    ) {

      categoryCounts["AI/ML"] =
        (categoryCounts["AI/ML"] || 0) + 1;
    }
  }
}

const totalJobs = items.length;

// -----------------------------------
// TOP TRENDING SKILLS
// -----------------------------------

const topSkills =

  Object.entries(skillCounts)

    .sort((a, b) => b[1] - a[1])

    .slice(0, 15)

    .map(([skill, count]) => {

      const percentage =

        Number(
          (
            (count / totalJobs) * 100
          ).toFixed(1)
        );

      return {
        skill,
        count,
        percentage
      };
    });

// -----------------------------------
// CATEGORY DISTRIBUTION
// -----------------------------------

const totalCategoryCount =

  Object.values(categoryCounts)
    .reduce((a, b) => a + b, 0);

const categoryDistribution =

  Object.entries(categoryCounts)

    .sort((a, b) => b[1] - a[1])

    .map(([category, count]) => {

      const percentage =

        Number(
          (
            (count / totalCategoryCount) * 100
          ).toFixed(1)
        );

      return {
        category,
        count,
        percentage
      };
    });
// -----------------------------------
// MARKET SUMMARY
// -----------------------------------

const topSkill =

  topSkills.length > 0
    ? topSkills[0].skill
    : "unknown";

// -----------------------------------
